package com.google.gson.internal;

import com.google.gson.stream.JsonReader;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.Method;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class JsonReaderInternalAccessTest {

    private JsonReaderInternalAccess jsonReaderInternalAccess;
    private JsonReader jsonReader;

    @BeforeEach
    void setUp() {
        // Since JsonReaderInternalAccess is abstract and INSTANCE is null,
        // create a mock subclass to test promoteNameToValue
        jsonReaderInternalAccess = mock(JsonReaderInternalAccess.class);
        jsonReader = mock(JsonReader.class);
    }

    @Test
    void testPromoteNameToValue_invocation() throws IOException {
        // Arrange
        doCallRealMethod().when(jsonReaderInternalAccess).promoteNameToValue(jsonReader);

        // Act & Assert
        // Since promoteNameToValue is abstract, this will not call real method,
        // so here we just verify that the method can be invoked via reflection

        // Use reflection to invoke promoteNameToValue
        try {
            Method method = JsonReaderInternalAccess.class.getDeclaredMethod("promoteNameToValue", JsonReader.class);
            method.setAccessible(true);
            // Invocation should throw AbstractMethodError because method is abstract
            assertThrows(AbstractMethodError.class, () -> method.invoke(jsonReaderInternalAccess, jsonReader));
        } catch (NoSuchMethodException e) {
            fail("Method promoteNameToValue not found");
        } catch (Exception e) {
            // InvocationTargetException wraps the AbstractMethodError
            Throwable cause = e.getCause();
            assertTrue(cause instanceof AbstractMethodError);
        }
    }
}
